class Solution {
    public int findIntegers(int n) {
        int k = 31 - Integer.numberOfLeadingZeros(n);
        int[] fib = new int[k + 3];
        fib[0] = 1;
        fib[1] = 2;
        for (int i = 2; i <= k + 1; ++i) {
            fib[i] = fib[i - 1] + fib[i - 2];
        }
        int res = 0;
        int prev = 0;
        for (int i = k; i >= 0; --i) {
            if ((n & (1 << i)) != 0) {
                res += fib[i + 1];
                if (prev == 1) return res;
                prev = 1;
            } else {
                prev = 0;
            }
        }
        return res + 1;
    }
}
